import {
  eip1271SignaturePayload,
  signOrderWithCustomEip1271,
  signOrderWithEip1271
} from "cow-sdk-wasm-test-package/nodejs";
import { describe, expect, test } from "vitest";
import { ORDER, OWNER } from "./orderbook.spec.js";

const SIGNATURE =
  "0x111111111111111111111111111111111111111111111111111111111111111122222222222222222222222222222222222222222222222222222222222222221b";
const EIP1271_SIGNATURE =
  "";

describe("EIP-1271 helpers", () => {
  test("encodes an EIP-1271 signature payload", () => {
    expect(eip1271SignaturePayload(ORDER, SIGNATURE)).toBe(EIP1271_SIGNATURE);
  });

  test("signs through typed data callback and wraps EIP-1271", async () => {
    const signed = await signOrderWithEip1271(ORDER, 1, OWNER, async (envelope: any) => {
      expect(envelope.primaryType).toBe("Order");
      return SIGNATURE;
    });

    expect(signed.signingScheme).toBe("eip1271");
    expect(signed.signature).toBe(EIP1271_SIGNATURE);
  });

  test("uses a custom EIP-1271 signature callback verbatim", async () => {
    const signed = await signOrderWithCustomEip1271(ORDER, 1, OWNER, async (request: any) => {
      expect(request.owner).toBe(OWNER);
      expect(request.typedData.primaryType).toBe("Order");
      return "0x1234";
    });

    expect(signed.signature).toBe("0x1234");
    expect(signed.signingScheme).toBe("eip1271");
  });
});
